  describe('notification ordering', () => {
    it('should deliver notifications in event order even when emitted concurrently', async () => {
      // Track the order in which the adapter delivers notifications
      const deliveryOrder: string[] = [];

      // Use a slow adapter: the order-created notification takes longer to
      // "send" than the status-changed notification. Without per-user
      // queuing, the status-changed notification would arrive first.
      const slowAdapter = {
        type: 'email' as const,
        async send(payload: NotificationPayload) {
          if (payload.subject.includes('Confirmation')) {
            // Simulate slow delivery for the first notification
            await new Promise((resolve) => setTimeout(resolve, 50));
          }
          deliveryOrder.push(payload.subject);
          return { success: true, messageId: `msg-${deliveryOrder.length}`, timestamp: new Date() };
        },
      };

      service.registerAdapter(slowAdapter);

      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const orderStatusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Emit both events concurrently — simulates rapid-fire domain events
      const p1 = eventBus.emit(orderCreatedEvent);
      const p2 = eventBus.emit(orderStatusChangedEvent);
      await Promise.all([p1, p2]);

      // The "Order Confirmation" notification must arrive before the
      // "Order Update" notification, despite the confirmation adapter
      // being slower.
      expect(deliveryOrder).toHaveLength(2);
      expect(deliveryOrder[0]).toContain('Order Confirmation');
      expect(deliveryOrder[1]).toContain('Order Update');

      // Verify stored notifications are also in correct order
      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[1]?.subject).toContain('Order Update');
    });

    it('should not block notifications for different users', async () => {
      // Verify that per-user queuing does not serialize across users
      const deliveryOrder: string[] = [];

      const slowAdapter = {
        type: 'email' as const,
        async send(payload: NotificationPayload) {
          if (payload.recipient === 'alice@example.com') {
            await new Promise((resolve) => setTimeout(resolve, 50));
          }
          deliveryOrder.push(`${payload.recipient}:${payload.subject}`);
          return { success: true, messageId: `msg-${deliveryOrder.length}`, timestamp: new Date() };
        },
      };

      service.registerAdapter(slowAdapter);

      const aliceEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const bobEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 20 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      // Emit concurrently — Alice's adapter is slow, Bob's is fast
      const p1 = eventBus.emit(aliceEvent);
      const p2 = eventBus.emit(bobEvent);
      await Promise.all([p1, p2]);

      // Bob's notification should arrive before Alice's because they
      // are independent users with separate queues
      expect(deliveryOrder).toHaveLength(2);
      expect(deliveryOrder[0]).toContain('bob@example.com');
      expect(deliveryOrder[1]).toContain('alice@example.com');
    });
  });
});

